import Foundation

struct CategoryContent6 {
    static let aiAtWork = CategoryData(
        id: "ai_at_work", name: "AI in Your Life", icon: "briefcase", colorName: "aiGreen",
        description: "How AI shows up in school, games, and everyday life",
        lessons: [lesson1, lesson2, lesson3, lesson4, lesson5, lesson6], order: 5,
        unlockRequirement: .completeCategoryMinimum("how_ai_learns")
    )
    static let lesson1 = LessonData(id: "aw_l1", title: "AI Productivity Tools", description: "Working smarter with AI", categoryId: "ai_at_work", questions: [
        Question(id: "aw1_q1", type: .multipleChoice, questionText: "An AI 'copilot' in the workplace refers to:", options: ["An AI assistant that augments human work on tasks like writing, coding, and analysis", "A fully autonomous system that makes business decisions without humans", "An automated calendar and scheduling application", "A hardware accelerator chip for office computers"], correctAnswer: "An AI assistant that augments human work on tasks like writing, coding, and analysis", explanation: "AI copilots from Microsoft, Google, Anthropic, and others assist workers rather than replace them, augmenting human capabilities in writing, coding, data analysis, and more."),
        Question(id: "aw1_q2", type: .trueFalse, questionText: "Major tech companies including Microsoft, Google, and Anthropic now offer AI assistants integrated into workplace productivity software.", options: ["True", "False"], correctAnswer: "True", explanation: "Microsoft 365 Copilot uses GPT, Google Workspace integrates Gemini, and Anthropic's Claude is embedded in enterprise tools — AI assistants are now standard across productivity suites."),
        Question(id: "aw1_q3", type: .matchPairs, questionText: "Match each AI-powered tool to its primary workplace function:", matchPairs: [
            MatchPair(term: "GitHub Copilot", definition: "AI-assisted coding"),
            MatchPair(term: "Claude for Enterprise", definition: "Research and document analysis"),
            MatchPair(term: "Google Gemini in Workspace", definition: "Email and document drafting"),
            MatchPair(term: "Midjourney", definition: "AI image generation for design")
        ], explanation: "AI productivity tools from different companies span coding, research, writing, and creative work across many industries."),
        Question(id: "aw1_q4", type: .fillInBlank, questionText: "AI __________ tools from companies like Anthropic, Google, and Microsoft help workers draft documents, analyze data, and automate routine tasks.", options: ["productivity", "compliance", "scheduling", "networking"], correctAnswer: "productivity", explanation: "AI productivity tools are designed to augment human work. Claude, Gemini, and Copilot each help workers accomplish tasks faster and more effectively."),
        Question(id: "aw1_q5", type: .scenarioJudgment, questionText: "An employee uses Claude to draft all their business reports and submits them without any review or editing. Is this best practice?", options: ["No, AI output should always be reviewed and verified by a human", "Yes, Claude and similar models are always perfectly accurate", "It depends on the length of the report"], correctAnswer: "No, AI output should always be reviewed and verified by a human", explanation: "Whether using Claude, Gemini, GPT, or any AI tool, output should always be reviewed by a human to ensure accuracy, appropriateness, and alignment with business needs."),
        Question(id: "aw1_q6", type: .multipleChoice, questionText: "What is the primary benefit of AI coding assistants like GitHub Copilot, Claude Code, and Gemini Code Assist?", options: ["Faster development through intelligent code suggestions and completions", "Complete elimination of all software bugs and errors", "Full replacement of human programmers in development teams", "Automatic creation of complete user interface designs"], correctAnswer: "Faster development through intelligent code suggestions and completions", explanation: "AI coding assistants from GitHub, Anthropic, Google, and others accelerate development with suggestions and completions, but developers remain essential for architecture, review, and quality.")
    ], order: 0, difficulty: .beginner)
    static let lesson2 = LessonData(id: "aw_l2", title: "AI in Hiring", description: "How AI is changing recruitment", categoryId: "ai_at_work", questions: [
        Question(id: "aw2_q1", type: .multipleChoice, questionText: "AI is most commonly used in the hiring process for:", options: ["Resume screening, candidate matching, and initial applicant filtering", "Making final hiring decisions autonomously without human involvement", "Eliminating the need for written job descriptions entirely", "Setting employee compensation based on social media profiles"], correctAnswer: "Resume screening, candidate matching, and initial applicant filtering", explanation: "Companies use AI tools from vendors like HireVue, Pymetrics, and others to screen large volumes of resumes and match candidates to positions based on qualifications."),
        Question(id: "aw2_q2", type: .trueFalse, questionText: "AI hiring tools have been found to exhibit gender and racial bias in multiple documented cases.", options: ["True", "False"], correctAnswer: "True", explanation: "Amazon's discontinued resume screener, studies on HireVue's video analysis, and audits of other tools have documented bias. This led to regulations like New York City's Local Law 144."),
        Question(id: "aw2_q3", type: .scenarioJudgment, questionText: "A company's AI resume screener automatically rejects candidates with employment gaps. Is this ethical?", options: ["No, it disproportionately harms caregivers, veterans, and people with disabilities", "Yes, employment continuity is a valid screening criterion", "It depends on the industry and job level"], correctAnswer: "No, it disproportionately harms caregivers, veterans, and people with disabilities", explanation: "This practice can disproportionately affect parents, caregivers, people with disabilities, military veterans, and others with legitimate reasons for career gaps — raising discrimination concerns."),
        Question(id: "aw2_q4", type: .fillInBlank, questionText: "AI hiring tools should be independently __________ on a regular basis to ensure they do not discriminate against protected groups.", options: ["audited", "minimized", "outsourced", "accelerated"], correctAnswer: "audited", explanation: "Regular bias audits help identify and correct discrimination. New York City, the EU AI Act, and Illinois all require or recommend auditing AI hiring systems."),
        Question(id: "aw2_q5", type: .multipleChoice, questionText: "New York City's Local Law 144 requires companies using AI in hiring to:", options: ["Conduct annual bias audits and notify candidates about AI use", "Use only AI for all hiring and promotion decisions", "Avoid all technology in their recruitment processes", "Share all employee performance data with the public"], correctAnswer: "Conduct annual bias audits and notify candidates about AI use", explanation: "NYC's Local Law 144 requires bias audits of automated employment decision tools and candidate notification — one of the first laws specifically targeting AI in hiring."),
        Question(id: "aw2_q6", type: .multipleChoice, questionText: "Which is a documented concern about AI-powered video interview analysis tools?", options: ["They may penalize candidates for accents, facial differences, or disabilities", "They make the interview process too convenient for candidates", "They are too slow to process video in real time", "They cost nothing to implement and maintain"], correctAnswer: "They may penalize candidates for accents, facial differences, or disabilities", explanation: "Research has shown AI video analysis can inadvertently penalize non-native speakers, people with facial differences, and those with disabilities — raising serious accessibility and discrimination concerns.")
    ], order: 1, difficulty: .intermediate)
    static let lesson3 = LessonData(id: "aw_l3", title: "Automation & Jobs", description: "Will AI take your job?", categoryId: "ai_at_work", questions: [
        Question(id: "aw3_q1", type: .multipleChoice, questionText: "According to research from McKinsey, the World Economic Forum, and MIT, AI automation is most likely to:", options: ["Transform and augment existing jobs rather than eliminate them entirely", "Replace all human workers within the next five years", "Have no measurable impact on employment patterns", "Only affect manufacturing and factory positions"], correctAnswer: "Transform and augment existing jobs rather than eliminate them entirely", explanation: "Major studies consistently predict AI will transform jobs rather than eliminate most of them. McKinsey estimates about 60% of occupations have at least 30% of activities that could be automated."),
        Question(id: "aw3_q2", type: .trueFalse, questionText: "Jobs requiring deep creativity, complex social intelligence, and empathy are generally more resistant to AI automation.", options: ["True", "False"], correctAnswer: "True", explanation: "Roles like therapy, nursing, creative direction, and teaching require human qualities that AI cannot fully replicate, making them more resistant to automation even as AI capabilities advance."),
        Question(id: "aw3_q3", type: .fillInBlank, questionText: "Tasks that are __________ and rule-based are the most likely to be automated by AI systems across all industries.", options: ["repetitive", "creative", "emotional", "physical"], correctAnswer: "repetitive", explanation: "Repetitive, rule-based, data-processing tasks are the easiest for AI to automate. This spans industries from finance to healthcare to logistics."),
        Question(id: "aw3_q4", type: .matchPairs, questionText: "Match each occupation to its level of AI automation risk:", matchPairs: [
            MatchPair(term: "Data entry clerk", definition: "High automation risk"),
            MatchPair(term: "Psychotherapist", definition: "Low automation risk"),
            MatchPair(term: "Customer service agent", definition: "Medium automation risk"),
            MatchPair(term: "Surgeon", definition: "AI-assisted, not replaced")
        ], explanation: "Different jobs face different automation risks. AI augments surgeons with tools like da Vinci robots but is unlikely to replace therapists who provide genuine human connection."),
        Question(id: "aw3_q5", type: .scenarioJudgment, questionText: "A marketing professional refuses to learn any AI tools, insisting that AI is a passing trend. Is this a sound career strategy?", options: ["No, AI fluency is rapidly becoming essential across most professions", "Yes, AI adoption will reverse in the coming years", "It depends on whether their company currently uses AI"], correctAnswer: "No, AI fluency is rapidly becoming essential across most professions", explanation: "AI tools from Anthropic, Google, Microsoft, Adobe, and Salesforce are being adopted across virtually every industry. AI literacy is becoming as important as digital literacy was a decade ago."),
        Question(id: "aw3_q6", type: .multipleChoice, questionText: "Which entirely new career field has emerged directly because of the rise of large language models?", options: ["Prompt engineering and AI integration specialist", "Data warehousing and storage administration", "Network security administration", "Desktop publishing and layout design"], correctAnswer: "Prompt engineering and AI integration specialist", explanation: "Prompt engineering emerged as companies like Anthropic, Google, and OpenAI released powerful language models. Related new roles include AI integration specialist, AI safety researcher, and AI ethics officer.")
    ], order: 2, difficulty: .intermediate)
    static let lesson4 = LessonData(id: "aw_l4", title: "AI Decision-Making", description: "When AI makes business choices", categoryId: "ai_at_work", questions: [
        Question(id: "aw4_q1", type: .multipleChoice, questionText: "Which business function can benefit from AI-powered decision support?", options: ["All of the above", "Inventory and supply chain management", "Dynamic pricing optimization", "Customer churn prediction and retention"], correctAnswer: "All of the above", explanation: "AI assists business decisions across supply chain, pricing, customer analytics, fraud detection, and more. Companies use models from Anthropic, Google, and others for these applications."),
        Question(id: "aw4_q2", type: .trueFalse, questionText: "AI should autonomously make all critical business decisions without any human oversight or review.", options: ["True", "False"], correctAnswer: "False", explanation: "Critical business decisions require human judgment. The EU AI Act mandates human oversight for high-risk AI applications, and industry best practices emphasize AI as a decision-support tool, not a replacement for human judgment."),
        Question(id: "aw4_q3", type: .fillInBlank, questionText: "An 'explainable AI' system can clearly show __________ it arrived at a specific decision or recommendation.", options: ["why", "when", "who", "where"], correctAnswer: "why", explanation: "Explainable AI (XAI) provides insights into reasoning, helping users trust and verify AI recommendations. The EU AI Act requires explainability for high-risk systems."),
        Question(id: "aw4_q4", type: .multipleChoice, questionText: "What is a 'black box' AI system in the context of business decision-making?", options: ["An AI whose internal decision process cannot be easily understood or explained", "An AI system that exclusively processes encrypted financial data", "An AI designed specifically for cybersecurity threat detection", "An AI that operates entirely offline without internet connectivity"], correctAnswer: "An AI whose internal decision process cannot be easily understood or explained", explanation: "Black box models produce outputs without revealing how they reached their conclusions. This lack of transparency is a major concern in regulated industries like finance and healthcare."),
        Question(id: "aw4_q5", type: .scenarioJudgment, questionText: "A bank uses an AI system to deny loan applications but cannot explain to rejected applicants why they were turned down. Is this acceptable?", options: ["No, financial decisions affecting individuals require transparent explanations", "Yes, proprietary AI models should not have to reveal their logic", "It depends on the size of the loan being requested"], correctAnswer: "No, financial decisions affecting individuals require transparent explanations", explanation: "Financial regulations in the EU, US, and elsewhere require lenders to explain adverse decisions. The EU AI Act classifies credit scoring AI as high-risk, demanding transparency and human oversight."),
        Question(id: "aw4_q6", type: .multipleChoice, questionText: "Why is human oversight essential in AI-powered business decision-making?", options: ["AI can make errors, lacks moral judgment, and may miss important context", "AI decisions are automatically legally binding in all jurisdictions", "Human brains process numerical data more accurately than computers", "AI systems are too slow for any real-time business decisions"], correctAnswer: "AI can make errors, lacks moral judgment, and may miss important context", explanation: "AI lacks ethical reasoning, can hallucinate facts, and may miss context that humans would catch. This is why Anthropic, Google, and regulators worldwide emphasize keeping humans in the loop.")
    ], order: 3, difficulty: .intermediate)
    static let lesson5 = LessonData(id: "aw_l5", title: "AI Skills for the Future", description: "Preparing for an AI world", categoryId: "ai_at_work", questions: [
        Question(id: "aw5_q1", type: .multipleChoice, questionText: "In an AI-driven workplace with tools from Anthropic, Google, Microsoft, and others, the most valuable professional skill is:", options: ["The ability to adapt and learn continuously as AI evolves", "Memorizing large volumes of factual information", "Avoiding all engagement with AI technology", "Working longer hours to outpace AI productivity"], correctAnswer: "The ability to adapt and learn continuously as AI evolves", explanation: "As AI from Anthropic, Google, Meta, and others evolves rapidly, continuous learning and adaptability are the most valuable professional skills across every industry."),
        Question(id: "aw5_q2", type: .trueFalse, questionText: "Only software engineers and data scientists need to understand how to work with AI tools.", options: ["True", "False"], correctAnswer: "False", explanation: "AI literacy is becoming essential across all professions. Lawyers use Claude for research, doctors use AI for diagnostics, marketers use Gemini for content, and teachers use AI for lesson planning."),
        Question(id: "aw5_q3", type: .matchPairs, questionText: "Match each future-ready skill to its description:", matchPairs: [
            MatchPair(term: "AI Literacy", definition: "Understanding AI capabilities and limitations"),
            MatchPair(term: "Data Fluency", definition: "Working with data effectively"),
            MatchPair(term: "Critical Thinking", definition: "Evaluating AI outputs for accuracy"),
            MatchPair(term: "Ethical Reasoning", definition: "Making values-based decisions about AI use")
        ], explanation: "These complementary skills prepare professionals to work effectively alongside AI tools from Anthropic, Google, Microsoft, and other providers."),
        Question(id: "aw5_q4", type: .fillInBlank, questionText: "__________ thinking — the ability to evaluate information for accuracy and reliability — becomes more important as AI models generate increasingly more content.", options: ["Critical", "Lateral", "Abstract", "Analytical"], correctAnswer: "Critical", explanation: "As models like Claude, Gemini, GPT, and Llama generate more content, the ability to critically evaluate AI output for accuracy, bias, and hallucinations becomes a crucial professional skill."),
        Question(id: "aw5_q5", type: .multipleChoice, questionText: "Which uniquely human capability remains the hardest for any current AI model to genuinely replicate?", options: ["Authentic empathy and emotional intelligence in complex situations", "Entering data into spreadsheets and databases quickly", "Performing arithmetic calculations on large datasets", "Recognizing statistical patterns in structured data"], correctAnswer: "Authentic empathy and emotional intelligence in complex situations", explanation: "While AI models can simulate empathetic language, genuine empathy and emotional intelligence in nuanced human situations remain distinctly human capabilities that no AI model can truly replicate."),
        Question(id: "aw5_q6", type: .scenarioJudgment, questionText: "A healthcare professional says they do not need to learn about AI because their hospital does not currently use it. Is this wise?", options: ["No, AI is being adopted across healthcare and nearly every industry", "Yes, some industries will never be affected by AI", "It depends on whether they work in a large or small hospital"], correctAnswer: "No, AI is being adopted across healthcare and nearly every industry", explanation: "AI is being rapidly adopted in healthcare for diagnostics, drug discovery, clinical documentation, and more. Google DeepMind's AlphaFold, Anthropic's Claude for research, and many specialized medical AI tools are transforming the field.")
    ], order: 4, difficulty: .beginner)
    static let lesson6 = LessonData(id: "aw_l6", title: "AI Business Strategy", description: "How companies adopt AI", categoryId: "ai_at_work", questions: [
        Question(id: "aw6_q1", type: .multipleChoice, questionText: "According to AI strategy experts, the first step in adopting AI for a business should be:", options: ["Identifying specific business problems where AI can deliver measurable value", "Purchasing the most expensive enterprise AI platform available", "Replacing all employees with AI automation immediately", "Ignoring AI entirely until competitors force adoption"], correctAnswer: "Identifying specific business problems where AI can deliver measurable value", explanation: "Successful AI adoption starts with real business problems, not technology. Whether using Claude, Gemini, or custom models, companies should identify where AI adds the most value first."),
        Question(id: "aw6_q2", type: .trueFalse, questionText: "Every company needs to build a custom AI model from scratch to benefit from artificial intelligence.", options: ["True", "False"], correctAnswer: "False", explanation: "Most companies benefit more from using existing AI services — APIs from Anthropic (Claude), Google (Gemini), OpenAI (GPT), and Meta (Llama) — rather than building custom models from scratch."),
        Question(id: "aw6_q3", type: .fillInBlank, questionText: "A successful AI strategy requires strong __________ governance to ensure the quality and security of information that AI systems depend on.", options: ["data", "talent", "technology", "marketing"], correctAnswer: "data", explanation: "Good data governance ensures quality, accessibility, and security of data. Whether a company uses Claude, Gemini, or custom models, poor data quality undermines any AI initiative."),
        Question(id: "aw6_q4", type: .multipleChoice, questionText: "According to industry surveys by Gartner and McKinsey, why do most enterprise AI projects fail?", options: ["Poor data quality combined with unclear business objectives", "Insufficient computing power and hardware limitations", "Too many competing AI frameworks and model choices", "Lack of executive enthusiasm for AI initiatives"], correctAnswer: "Poor data quality combined with unclear business objectives", explanation: "Studies consistently show that unclear objectives and inadequate data — not technology limitations — are the primary reasons AI projects fail across industries."),
        Question(id: "aw6_q5", type: .scenarioJudgment, questionText: "A startup claims their AI product 'outperforms any human expert in every situation.' Should investors be cautious about this claim?", options: ["Yes, overly broad AI superiority claims are usually misleading", "No, modern AI genuinely surpasses humans at everything", "It depends on the startup's funding amount"], correctAnswer: "Yes, overly broad AI superiority claims are usually misleading", explanation: "Responsible AI companies like Anthropic and Google DeepMind carefully scope their performance claims. Overly broad claims of AI superiority are a red flag that warrants skeptical evaluation."),
        Question(id: "aw6_q6", type: .multipleChoice, questionText: "What does the 'AI readiness' of an organization measure?", options: ["How prepared the organization is to successfully adopt and benefit from AI", "How many AI software licenses the organization has purchased", "The total headcount of the organization's data science team", "Whether the organization uses cloud computing infrastructure"], correctAnswer: "How prepared the organization is to successfully adopt and benefit from AI", explanation: "AI readiness encompasses data infrastructure, talent, organizational culture, governance, and leadership alignment — all necessary for successful adoption of tools from Anthropic, Google, Microsoft, and others.")
    ], order: 5, difficulty: .advanced)
}
